            <div style={{ width: 72, height: 72, borderRadius: '50%', background: 'var(--primary)',
              border: '4px solid var(--surface)', display: 'flex', alignItems: 'center',
              justifyContent: 'center', fontSize: 28, fontWeight: 700, color: '#fff', flexShrink: 0 }}>
              {avatarLetter}
